#!/usr/bin/env node

import { Command } from 'commander';
import { loadConfig } from './config';
import { MarkdownCLIConfig } from './types';
import chalk from 'chalk';
import path from 'path';
import fs from 'fs';

const pkg = JSON.parse(fs.readFileSync(path.join(__dirname, '../package.json'), 'utf-8'));

const program = new Command();

program
  .name('markdown-cli')
  .description('A powerful Markdown processing CLI tool')
  .version(pkg.version)
  .option('-c, --config <path>', 'й…ҚзҪ®ж–Үд»¶и·Ҝеҫ„')
  .option('--no-color', 'зҰҒз”ЁйўңиүІиҫ“еҮә')
  .option('-t, --theme <theme>', 'дё»йўҳ (default|monokai|github|dracula)', 'default');

// convert е‘Ҫд»Ө вҖ” иҪ¬жҚў Markdown ж–Үд»¶
program
  .command('convert <file>')
  .description('иҪ¬жҚў Markdown ж–Үд»¶еҲ°з»Ҳз«Ҝиҫ“еҮәжҲ–жҢҮе®ҡж јејҸ')
  .option('-o, --output <file>', 'иҫ“еҮәеҲ°ж–Үд»¶')
  .option('-f, --format <format>', 'иҫ“еҮәж јејҸ (terminal|html|json)', 'terminal')
  .option('--line-numbers', 'жҳҫзӨәиЎҢеҸ·')
  .option('--max-width <n>', 'жңҖеӨ§е®ҪеәҰ', '80')
  .action(async (file: string, opts: any) => {
    const config = loadConfig(program.opts().config);
    const { MarkdownParser } = await import('./parser');
    const { TerminalRenderer } = await import('./renderer');
    const { OutputManager } = await import('./output');
    const { PluginLoader } = await import('./plugins/plugin-loader');

    const content = fs.readFileSync(file, 'utf-8');
    const plugins = new PluginLoader(config);
    await plugins.loadAll();

    const parser = new MarkdownParser(config);
    let result = parser.parse(content);
    result = plugins.runAfterParse(result);

    const renderer = new TerminalRenderer({
      theme: (program.opts().theme || config.theme) as any,
      lineNumbers: opts.lineNumbers || config.lineNumbers,
      maxWidth: parseInt(opts.maxWidth) || config.maxWidth,
      colorEnabled: program.opts().color !== false && config.output.colorEnabled,
    });

    let tokens = plugins.runBeforeRender(result.tokens);
    let output = renderer.render(tokens);
    output = plugins.runAfterRender(output);

    const outputManager = new OutputManager();
    if (opts.output) {
      await outputManager.write({ target: 'file', filePath: opts.output, format: opts.format }, output);
    } else {
      await outputManager.write({ target: 'stdout', format: opts.format }, output);
    }
  });

// format е‘Ҫд»Ө вҖ” ж јејҸеҢ– Markdown ж–Үд»¶
program
  .command('format <files...>')
  .description('ж јејҸеҢ– Markdown ж–Үд»¶пјҲеҺҹең°дҝ®ж”№жҲ–иҫ“еҮәпјү')
  .option('-w, --write', 'еҺҹең°дҝ®ж”№ж–Үд»¶')
  .option('--check', 'д»…жЈҖжҹҘпјҢдёҚдҝ®ж”№')
  .action(async (files: string[], opts: any) => {
    const config = loadConfig(program.opts().config);
    const { MarkdownFormatter } = await import('./formatter');
    const formatter = new MarkdownFormatter(config);

    let hasErrors = false;
    for (const pattern of files) {
      const { glob } = await import('glob');
      const matched = await glob(pattern);
      for (const file of matched) {
        const content = fs.readFileSync(file, 'utf-8');
        const formatted = formatter.format(content);
        if (content !== formatted) {
          if (opts.check) {
            console.log(chalk.yellow(`вң— ${file} вҖ” йңҖиҰҒж јејҸеҢ–`));
            hasErrors = true;
          } else if (opts.write) {
            fs.writeFileSync(file, formatted, 'utf-8');
            console.log(chalk.green(`вң“ ${file} вҖ” е·Іж јејҸеҢ–`));
          } else {
            process.stdout.write(formatted);
          }
        } else {
          console.log(chalk.gray(`в—Ӣ ${file} вҖ” ж— йңҖдҝ®ж”№`));
        }
      }
    }
    if (opts.check && hasErrors) process.exit(1);
  });

// lint е‘Ҫд»Ө вҖ” жЈҖжҹҘ Markdown и§„иҢғ
program
  .command('lint <files...>')
  .description('жЈҖжҹҘ Markdown ж–Үд»¶и§„иҢғ')
  .action(async (files: string[]) => {
    const config = loadConfig(program.opts().config);
    const { MarkdownParser } = await import('./parser');
    const parser = new MarkdownParser(config);

    let totalErrors = 0;
    for (const file of files) {
      if (!fs.existsSync(file)) { console.error(chalk.red(`ж–Үд»¶дёҚеӯҳеңЁ: ${file}`)); continue; }
      const content = fs.readFileSync(file, 'utf-8');
      const result = parser.parse(content);
      if (result.errors.length > 0) {
        console.log(chalk.underline(file));
        for (const err of result.errors) {
          const icon = err.severity === 'error' ? chalk.red('вң—') : chalk.yellow('вҡ ');
          console.log(`  ${icon} ${err.line}:${err.column} вҖ” ${err.message}`);
        }
        totalErrors += result.errors.length;
      }
    }
    console.log(`\nжЈҖжҹҘе®ҢжҲҗ: ${totalErrors} дёӘй—®йўҳ`);
    if (totalErrors > 0) process.exit(1);
  });

// watch е‘Ҫд»Ө вҖ” зӣ‘еҗ¬ж–Үд»¶еҸҳеҢ–
program
  .command('watch <file>')
  .description('зӣ‘еҗ¬ Markdown ж–Үд»¶еҸҳеҢ–е№¶е®һж—¶йў„и§Ҳ')
  .action(async (file: string) => {
    const config = loadConfig(program.opts().config);
    const { FileWatcher } = await import('./watcher');
    const watcher = new FileWatcher(config);
    watcher.watch(file);
  });

program.parse();
