  heading: chalk.Chalk; code: chalk.Chalk; codeBlock: chalk.Chalk; codeBorder: chalk.Chalk;
  link: chalk.Chalk; emphasis: chalk.Chalk; strong: chalk.Chalk; blockquote: chalk.Chalk;
