import chokidar, { FSWatcher } from 'chokidar';
import fs from 'fs';
import chalk from 'chalk';
import { MarkdownCLIConfig } from './types';
import { MarkdownParser } from './parser';
import { TerminalRenderer } from './renderer';

export class FileWatcher {
  private config: MarkdownCLIConfig;
  private watcher: FSWatcher | null = null;
  private debounceTimer: NodeJS.Timeout | null = null;
  private parser: MarkdownParser;
  private renderer: TerminalRenderer;

  constructor(config: MarkdownCLIConfig) {
    this.config = config;
    this.parser = new MarkdownParser(config);
    this.renderer = new TerminalRenderer({
      theme: config.theme,
      lineNumbers: config.lineNumbers,
      maxWidth: config.maxWidth,
      colorEnabled: config.output.colorEnabled,
    });
  }

  watch(filePath: string): void {
    console.log(chalk.cyan(`\nрҹ‘Җ зӣ‘еҗ¬дёӯ: ${filePath}`));
    console.log(chalk.dim('  жҢү Ctrl+C еҒңжӯў\n'));

    // йҰ–ж¬ЎжёІжҹ“
    this.render(filePath);

    this.watcher = chokidar.watch(filePath, {
      persistent: true,
      ignoreInitial: true,
      awaitWriteFinish: { stabilityThreshold: 100 },
    });

    this.watcher.on('change', () => {
      if (this.debounceTimer) clearTimeout(this.debounceTimer);
      this.debounceTimer = setTimeout(() => {
        console.clear();
        console.log(chalk.cyan(`\nрҹ”„ ж–Үд»¶еҸҳеҢ–: ${filePath} вҖ” ${new Date().toLocaleTimeString()}\n`));
        this.render(filePath);
      }, this.config.watch.debounce);
    });

    this.watcher.on('error', (err) => {
      console.error(chalk.red(`зӣ‘еҗ¬й”ҷиҜҜ: ${err.message}`));
    });

    // дјҳйӣ…йҖҖеҮә
    const cleanup = () => { this.stop(); process.exit(0); };
    process.on('SIGINT', cleanup);
    process.on('SIGTERM', cleanup);
  }

  stop(): void {
    if (this.debounceTimer) {
      clearTimeout(this.debounceTimer);
      this.debounceTimer = null;
    }
    if (this.watcher) {
      this.watcher.close();
      this.watcher = null;
    }
    console.log(chalk.dim('\nзӣ‘еҗ¬е·ІеҒңжӯў'));
  }

  private render(filePath: string): void {
    try {
      const content = fs.readFileSync(filePath, 'utf-8');
      const result = this.parser.parse(content);
      const output = this.renderer.render(result.tokens);
      console.log(output);
      if (result.errors.length > 0) {
        console.log(chalk.yellow(`\nвҡ  ${result.errors.length} дёӘ lint иӯҰе‘Ҡ`));
      }
    } catch (err: any) {
      console.error(chalk.red(`жёІжҹ“еӨұиҙҘ: ${err.message}`));
    }
  }
}
