```

The `[slug].js` file will be responsible for rendering individual project pages dynamically based on the project slug.

---

### Step 2: Implement `getStaticPaths` and `getStaticProps`

In `[slug].js`, use `getStaticPaths` to generate paths for all projects and `getStaticProps` to fetch the data for each individual project.

HereвҖҷs an example implementation:

```jsx
import fs from 'fs';
import path from 'path';
import matter from 'gray-matter';
import { serialize } from 'next-mdx-remote/serialize';
import { MDXRemote } from 'next-mdx-remote';

export default function ProjectPage({ source, frontMatter }) {
  return (
    <div className="max-w-4xl mx-auto px-4 py-12">
      <h1 className="text-4xl font-bold mb-4">{frontMatter.title}</h1>
      <p className="text-gray-600 mb-6">{frontMatter.description}</p>
      <div className="flex flex-wrap gap-2 mb-6">
        {frontMatter.tags.map((tag) => (
          <span
            key={tag}
            className="bg-blue-100 text-blue-600 px-3 py-1 rounded-full text-sm font-medium"
          >
            {tag}
          </span>
        ))}
      </div>
      <img
        src={frontMatter.image}
        alt={frontMatter.title}
        className="w-full h-64 object-cover mb-8 rounded-lg"
      />
      <article className="prose lg:prose-xl">
        <MDXRemote {...source} />
      </article>
    </div>
  );
}

export async function getStaticPaths() {
  const projectsDirectory = path.join(process.cwd(), 'content/projects');
  const filenames = fs.readdirSync(projectsDirectory);

  const paths = filenames.map((filename) => ({
    params: { slug: filename.replace('.mdx', '') },
  }));

  return {
    paths,
    fallback: false, // Set to 'true' or 'blocking' if you want incremental builds
  };
}

export async function getStaticProps({ params }) {
  const { slug } = params;
  const filePath = path.join(process.cwd(), 'content/projects', `${slug}.mdx`);
  const fileContents = fs.readFileSync(filePath, 'utf8');
  const { data, content } = matter(fileContents);

  // Serialize MDX content
  const source = await serialize(content);

  return {
    props: {
      source,
      frontMatter: data,
    },
  };
}
```

