      reconnectAttempts.current = 0; // Reset attempts on successful connection
    };

    ws.current.onmessage = (event) => {
      console.log('Message received:', event.data);
      // Handle incoming messages here
    };

    ws.current.onclose = (event) => {
      console.log('WebSocket connection closed:', event);
      attemptReconnection();
    };

    ws.current.onerror = (error) => {
      console.error('WebSocket error:', error);
      ws.current.close();
    };
  };

  const attemptReconnection = () => {
    reconnectAttempts.current++;

    const delay = Math.min(1000 * Math.pow(2, reconnectAttempts.current), 30000); // Exponential backoff up to 30 seconds
    console.log(`Attempting to reconnect in ${delay / 1000} seconds...`);

    reconnectTimeout.current = setTimeout(() => {
      connectWebSocket();
    }, delay);
  };

  useEffect(() => {
    connectWebSocket();

    return () => {
      if (ws.current) {
        ws.current.close();
      }

      if (reconnectTimeout.current) {
        clearTimeout(reconnectTimeout.current);
      }
    };
  }, [url]);

  return ws;
};

const WebSocketComponent = () => {
  const ws = useWebSocket('wss://your-websocket-url');

  return (
    <>
      <Text>WebSocket Example</Text>
    </>
  );
};

export default WebSocketComponent;
```

### Key Features:
- **`useWebSocket` hook**: Encapsulates the WebSocket logic, including reconnection handling.
- **Exponential backoff**: Ensured with a simple formula using `Math.pow`.
- **Cleanup**: React's `useEffect` ensures that when the component is unmounted, the WebSocket connection is closed and any pending reconnection attempts are canceled.

You can adapt the `handleMessage` logic inside `onmessage` to suit your application's needs. Let me know if you need help refining it further!

